import play.api.mvc._
import slick.jdbc.PostgresProfile.api._

class ProductSearchController @Inject()(val controllerComponents: ControllerComponents, dbConfigProvider: DatabaseConfigProvider) extends BaseController {

  private val db = dbConfigProvider.get[JdbcProfile]

  def search = Action { implicit request =>
    val query = request.queryString
    val filters = query.map { case (key, value) => key -> value.head }.toMap

    val whereClause = buildWhereClause(filters)

    val sqlQuery = sql"SELECT * FROM products WHERE $whereClause".as[Product]

    db.run(sqlQuery.result).map(products => Ok(views.html.products(products)))
